With some inputs of convex polygons that are entirely disjoint, `intersectConvexConvex` does not return an empty polygon as one would expect, but rather one of the input polygons.
**intersection.cpp**
```cpp
#include <opencv2/opencv.hpp>

#include <iostream>
#include <vector>

std::ostream &operator<<(std::ostream &out, std::vector<cv::Point> const &v) {
  bool first = true;
  for (auto p : v) {
    if (!first) {
      out << ' ';
    }
    out << p;
    first = false;
  }
  return out;
}

int main() {
  std::vector<cv::Point> a = {{290, 126}, {284, 132}, {281, 133}, {256, 124}, {249, 116}, {234, 91}, {232, 86}, {232, 79}, {251, 69}, {257, 68}, {297, 85}, {299, 87}};
  std::vector<cv::Point> b = {{192, 236}, {190, 245}, {177, 260}, {154, 271}, {142, 270}, {135, 263}, {131, 254}, {132, 240}, {172, 213}, {176, 216}};
  std::vector<cv::Point> i;
  cv::intersectConvexConvex(a, b, i);

  std::cout << "A: " << cv::isContourConvex(a) << ' ' << a << '\n';
  std::cout << "B: " << cv::isContourConvex(b) << ' ' << b << '\n';
  std::cout << "I: " << "  " << i << '\n';

  cv::Mat image(360, 640, CV_8UC3);
  cv::polylines(image, { a }, true, cv::Scalar(0, 0, 255), 2);
  cv::polylines(image, { b }, true, cv::Scalar(0, 255, 0), 2);
  cv::polylines(image, { i }, true, cv::Scalar(255, 0, 0));

  cv::namedWindow("Intersection");
  cv::imshow("Intersection", image);
  cv::waitKey(0);
}
```
Compile and run with:
```bash
$ g++ -Wall -ointersect intersect.cc -lopencv_imgproc -lopencv_highgui -lopencv_core && ./intersect 
```
Output:
```
A: 1 [290, 126] [284, 132] [281, 133] [256, 124] [249, 116] [234, 91] [232, 86] [232, 79] [251, 69] [257, 68] [297, 85] [299, 87]
B: 1 [192, 236] [190, 245] [177, 260] [154, 271] [142, 270] [135, 263] [131, 254] [132, 240] [172, 213] [176, 216]
I:   [290, 126] [284, 132] [281, 133] [256, 124] [249, 116] [234, 91] [232, 86] [232, 79] [251, 69] [257, 68] [297, 85] [299, 87]
```
![2017-11-08-110235_640x360_scrot](https://user-images.githubusercontent.com/90930/32542904-5c28cee4-c474-11e7-98c6-a46a6251e7bd.png)
Note how the blue line of the intersection is on top of the red line of polygon A.
Expected output:
```
A: 1 [290, 126] [284, 132] [281, 133] [256, 124] [249, 116] [234, 91] [232, 86] [232, 79] [251, 69] [257, 68] [297, 85] [299, 87]
B: 1 [192, 236] [190, 245] [177, 260] [154, 271] [142, 270] [135, 263] [131, 254] [132, 240] [172, 213] [176, 216]
I:   
```
