/*! display Mat on Picture Control in MFC
*! Mat  img: the image that to display
*! UINT nID: the ID of control
*! support BGR(Mat default),BGRA,GARY
*! other type need use cvtColor to convert
*/
void ImageDlg::DrawMat(cv::Mat *srcImg, UINT nID)
{
	if (srcImg->empty() || srcImg->data == nullptr) {
		return;
	}

	CDC *pDC = nullptr;
	CWnd *pWnd = GetDlgItem(nID);
	pWnd->GetClientRect(&draw_rect);
	pDC = pWnd->GetDC();
	cv::resize(*srcImg, mat2bitmap_img, cv::Size(draw_rect.Width(), draw_rect.Height()));
	switch (srcImg->channels())
	{
	case 1:
		cv::cvtColor(mat2bitmap_img, mat2bitmap_img, CV_GRAY2BGRA); // GRAY --> BGRA(CV_8UC4)
		break;
	case 3:
		cv::cvtColor(mat2bitmap_img, mat2bitmap_img, CV_BGR2BGRA);  // BGR --> BGRA(CV_8UC4)
		break;
	default:
		break;
	}

	// why convert to CV_8UC4
	// because windows need 4-byte aligned in a row
	// if there are 3 pixels in a row,
	// CV_8UC3: 3 pixel = 9 bytes,   9 % 4 = 1(no alignment)
	// CV_8UC4: 3 pixel = 12 bytes, 12 % 4 = 0(it's ok)

	// calculate how many bytes a pixel
	int  pixelBytes = mat2bitmap_img.channels()*(mat2bitmap_img.depth() + 1);

	// create a header by using BITMAPINFO structure
	draw_bitmapInfo.bmiHeader.biBitCount = 8 * pixelBytes;
	draw_bitmapInfo.bmiHeader.biWidth = mat2bitmap_img.cols;
	draw_bitmapInfo.bmiHeader.biHeight = -mat2bitmap_img.rows;

	// display Mat
	// Mat data + BITMAPINFO --> MFC DigItem
	::StretchDIBits(
		pDC->GetSafeHdc(),
		draw_rect.left, draw_rect.top, draw_rect.Width(), draw_rect.Height(),
		0, 0, draw_rect.Width(), draw_rect.Height(),
		mat2bitmap_img.data,
		&draw_bitmapInfo,
		DIB_RGB_COLORS,
		SRCCOPY
	);
	ReleaseDC(pDC);
	pDC = nullptr;
	pWnd = nullptr;
}

