                    REQUEST_WRITE_PERMISSION);
        } else {
            try {
                FileWriter fileWriter = new FileWriter(mOutputPath.getAbsolutePath().replace(".mp4", "") + ".json");
                fileWriter.write(jsonFile.toString());
                fileWriter.flush();
                fileWriter.close();
            } catch (IOException e) {
                e.printStackTrace();
            }


        }
    }

