    protected boolean writeXMLJava() {
        String sdCard = getExternalStorageDirectory().toString();
        File dir = new File(sdCard, ".wellness/outputXml/");
        dir.mkdirs();
        File file = new File(dir, "confinement.xml");
        try {
            FileOutputStream f = new FileOutputStream(file);
            PrintWriter pw = new PrintWriter(f);
            pw.println(outputXmlwrite());
            pw.flush();
            pw.close();
            f.close();
        } catch (FileNotFoundException e) {
            e.printStackTrace();
            Log.i("File not found", "******* File not found. Did you" +
                    " add a WRITE_EXTERNAL_STORAGE permission to the   manifest?");
            return false;
        } catch (IOException e) {
            e.printStackTrace();
            return false;
        } catch (Exception e) {
            e.printStackTrace();
        }
        return true;
    }

