            mIsCompressingVideo = false;
            Toast.makeText(OpencvVideoCapture.this, "Please wait...", Toast.LENGTH_LONG).show();
        } else {
            if (mTimerStarted) {
                myOrientationEventListener.disable();
                resetProcess();
                if (mOpenCvCameraView != null) {
