    private void getVideoDuration(File path) {
        MediaMetadataRetriever retriever = new MediaMetadataRetriever();
//use one of overloaded setDataSource() functions to set your data source
        retriever.setDataSource(OpencvVideoCapture.this, Uri.fromFile(path));
        String time = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_DURATION);
        long timeInMillisec = Long.parseLong(time);
        long seconds = TimeUnit.MILLISECONDS.toSeconds(timeInMillisec);
        if (mReport) {
            mReport = false;
            getPathToZip();
        } else {
            if (seconds > 50) {
                getPathToZip();
            } else {
                String mFileName = mFile264.getPath().substring(0, mFile264.getPath().lastIndexOf("/")).trim();
//            String mFileName = getVideoPath();
                System.out.println("delete file :" + mFileName);
                File file = new File(mFileName);
                deleteRecursive(file);
                Utils.mLessDuration = true;
                finish();
            }
        }
        System.out.println("videoduration :" + seconds);
    }



