                        mProgressDialog.setCancelable(false);
                        mProgressDialog.show();
                    } catch (Exception e) {
                        e.printStackTrace();
                    }
                }

                @Override
                public void onFinish() {
                    mIsCompressingVideo = false;
                    System.out.println("outvid finish :");
                    Log.d(TAG, "Finished command : ffmpeg " + command);
                    try {
                        deleteRecursive(mFile264);
                        mProgressDialog.dismiss();
                        getVideoDuration(mOutputPath);
                    } catch (Exception e) {

                    }
                }
            });
        } catch (FFmpegCommandAlreadyRunningException e) {
            e.printStackTrace();
        }
    }

