     unsigned char G = *in++;
     unsigned char B = *in++;
     unsigned short hue_value = RGBtoD(R, G, B);

     if(hue_value > 0)
     {
      if(!is_disparity)
      {
       unsigned short z_value = static_cast<unsigned short>((min_depth + (max_depth - min_depth) * hue_value / 1529.0f) / depth_units); //1529
       *out++ = z_value;
      }
      else
      {
       float disp_value = min_disparity + (max_disparity - min_disparity) * hue_value / 1529.0;//1529
       *out++ = static_cast<unsigned short>((1.0f / disp_value)/depth_units + 0.5);
      }
     }
     else
     {
      *out++ = 0;
     }
    }
   }
  }
  void ComputePointCloud(cv::Mat& depth_mat, std::vector<float>& point_cloud)
  {
   float depth_units = 0.0010;
   point_cloud.clear();
   for (int y = 0; y < 480; y++)
   {
    for (int x = 0; x < 848; x++)
    {
     auto depth_value = depth_mat.at<unsigned short>(y, x);
     if (depth_value > 0)
     {
      point_cloud.push_back(depth_value * (x - 419.7328186035156) / 424.0969543457031 * depth_units * 1000.0f );	//* 1000.0f
      point_cloud.push_back(depth_value * (y - 237.46710205078125) / 424.0969543457031 * depth_units * 1000.0f );//* 1000.0f
      point_cloud.push_back((float)depth_value * depth_units * 1000.0f );//* 1000.0f
     }
    }
   }
  }


