	std::vector<float> points;
	float depth_scale = 0.0010;
	Eigen::Matrix3f K;
	Eigen::Matrix3f invK;
	K << 424.0969543457031, 0.0, 419.7328186035156, 0.0, 424.0969543457031, 237.46710205078125, 0.0, 0.0, 1.0;
	invK = K.inverse();	

	for (int i=0;i<depth_mat.rows;i++)
	{
	 const unsigned short* row_ptr = depth_mat.ptr<unsigned short>(i);
	 for (int j=0;j<depth_mat.cols;j++)
	 {
	  unsigned short id = row_ptr[j];
	  if(id!=0)
	  {
	   float d=depth_scale*id;
           Eigen::Vector3f image_point(j*d,i*d,d);
