	   points.push_back(camera_point.x());
	   points.push_back(camera_point.y());
	   points.push_back(camera_point.z());
	  }
	 }
	}

	int n_points = points.size();
	sensor_msgs::PointCloud2 cloud_msg;
	sensor_msgs::PointCloud2Modifier modifier(cloud_msg);
	modifier.setPointCloud2Fields(3, "x", 1, sensor_msgs::PointField::UINT16, "y", 1, sensor_msgs::PointField::UINT16,"z", 1, sensor_msgs::PointField::UINT16); //FLOAT32
