	sensor_msgs::PointCloud2Iterator<float> iter_y(cloud_msg, "y");
	sensor_msgs::PointCloud2Iterator<float> iter_z(cloud_msg, "z");
	cloud_msg.height = 1;
	cloud_msg.width = n_points;
	cloud_msg.header.frame_id = msg->header.frame_id;
	cloud_msg.header.seq = msg->header.seq;
	cloud_msg.header.stamp = msg->header.stamp;
    	
	for(size_t i=0; i<n_points/3; ++i, ++iter_x, ++iter_y, ++iter_z)
	{
	 *iter_x = points[3*i+0];
	 *iter_y = points[3*i+1];
	 *iter_z = points[3*i+2];
	 //std::cerr << *iter_x << " " << *iter_y << " " << *iter_z << std::endl;	// It display x,y,z points' coordinates on terminal.
	}

	cloud_pub.publish(cloud_msg);
